using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateSampleItems() =>
    [
        new OrderItem { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
        new OrderItem { ProductName = "Gadget", Price = 25.50m, Quantity = 1 },
    ];

    [TestMethod]
    public void CreateOrder_WithValidInput_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var items = CreateSampleItems();

        // Act
        var order = _service.CreateOrder("customer-1", items);

        // Assert
        Assert.AreEqual("customer-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidInput_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = CreateSampleItems(); // (10 * 2) + (25.50 * 1) = 45.50

        // Act
        var order = _service.CreateOrder("customer-1", items);

        // Assert
        Assert.AreEqual(45.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithValidInput_AssignsNonEmptyId()
    {
        // Arrange
        var items = CreateSampleItems();

        // Act
        var order = _service.CreateOrder("customer-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidInput_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var items = CreateSampleItems();
        var before = DateTime.UtcNow;

        // Act
        var order = _service.CreateOrder("customer-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = CreateSampleItems();

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("customer-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        // Arrange
        var emptyItems = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("customer-1", emptyItems));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var items = CreateSampleItems();
        var created = _service.CreateOrder("customer-1", items);

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreEqual(created.CustomerId, retrieved.CustomerId);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        // Act
        var result = _service.GetOrder("non-existent-id");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithMatchingOrders_ReturnsAllCustomerOrders()
    {
        // Arrange
        var items = CreateSampleItems();
        _service.CreateOrder("customer-A", items);
        _service.CreateOrder("customer-A", items);
        _service.CreateOrder("customer-B", items);

        // Act
        var orders = _service.GetOrdersByCustomer("customer-A");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoMatchingOrders_ReturnsEmptyList()
    {
        // Act
        var orders = _service.GetOrdersByCustomer("unknown-customer");

        // Assert
        Assert.IsEmpty(orders);
    }

    [TestMethod]
    [DataRow(1)]
    [DataRow(3)]
    [DataRow(5)]
    public void CreateOrder_WithMultipleItems_IncludesAllItemsInOrder(int itemCount)
    {
        // Arrange
        var items = Enumerable.Range(1, itemCount)
            .Select(i => new OrderItem { ProductName = $"Item {i}", Price = 10m, Quantity = 1 })
            .ToList();

        // Act
        var order = _service.CreateOrder("customer-1", items);

        // Assert
        Assert.HasCount(itemCount, order.Items);
    }
}

